SELECT o.object_id, op.property_id, op.property_value
FROM objects o
JOIN object_properties op ON o.object_id = op.object_id;

SELECT object_name, object_description
FROM objects
ORDER BY created_at DESC;

SELECT property_id, COUNT(DISTINCT object_id) AS unique_object_count
FROM object_properties
GROUP BY property_id;

SELECT object_property_id, COUNT(*) AS TotalIssues
FROM data_quality_issues
GROUP BY object_property_id;

SELECT 
    (SELECT COUNT(*) FROM objects) + 
    (SELECT COUNT(*) FROM data_quality_issues) AS GrandTotal;

SELECT p.property_name, op.property_value
FROM properties p
JOIN object_properties op ON p.property_id = op.property_id;
